INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかったイヤリング。\n装備者に活力加速を与える。", 11001, 0, 1800, "加速の玉飾り", 1, 1, 1, 10, "ＴＰ上昇＋5", 11001);
