INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった首飾り。\n敵に異常を与えやすくなる。", 12001, 0, 1800, "紫晶ビザリオ", 2, 1, 1, 10, "状態異常命中＋20", 12001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった杖。所持する\nだけで敵を呪うことができる。", 12002, 0, 1800, "魔杖メジナエ", 2, 1, 1, 10, "敵全体に呪い付与（毎秒【弱体】数×500ダメージ）", 12002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった短剣。持つだ\nけで敵を毒にすることができる。", 12003, 0, 1800, "暗剣ポワゾン", 2, 1, 1, 10, "敵全体に毒付与（毎秒【弱体】数×500ダメージ）", 12003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった帽子。装備す\nると敵の攻撃を弱体させる。", 12004, 0, 1800, "破守帽ディスペル", 2, 1, 1, 10, "敵の物理/魔法攻撃力－10％", 12004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった刀。\n敵の守りを断ち崩す力がある。", 12005, 0, 1800, "崩刀ヤマツキ", 2, 1, 1, 10, "敵の物理/魔法防御力－10％", 12005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった槍。鋭い一撃\nで敵に深い傷を負わせる。", 13001, 0, 1800, "キラースピア", 3, 1, 1, 10, "敵の物理/魔法被クリダメ＋10％", 13001);
