INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった籠手。強化\nされた一撃を放つことができる。", 13003, 0, 1800, "クリーヴフィスト", 3, 1, 1, 10, "通常攻撃強化＋30", 13003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で⾒つかった⼸。装備する\nと致命の一射を与えやすくなる。", 13004, 0, 1800, "クリティカルアーク", 3, 1, 1, 10, "物理/魔法クリティカル＋10％", 13004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった斧。攻撃と共\nに敵の体力を吸い取る力を宿す。", 13005, 0, 1800, "アブゾーブハチェット", 3, 1, 1, 10, "ＨＰ吸収＋10", 13005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった耳飾り。装備\n者の強化効果を高める。", 14001, 0, 1800, "強化のジェム", 4, 1, 1, 10, "バフ強化＋30", 14001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で⾒つかった鎧。同朋の\n強靭を、自身の攻撃に変換する。", 14002, 0, 1800, "抗鉄のプレート", 4, 1, 1, 10, "物理/魔法攻撃力アップ\n（先頭キャラの物理防御力×5）", 14002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で⾒つかったドレス。装備\n者の抗魔の才を攻撃⼒に換える。", 14003, 0, 1800, "抗魔のドレス", 4, 1, 1, 10, "物理/魔法攻撃力アップ\n（先頭キャラの魔法防御力×5）", 14003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった大剣。装備者\nの攻撃力を強化する。", 14004, 0, 1800, "蛇紋のツルギ", 4, 1, 1, 10, "物理/魔法攻撃力＋20％", 14004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった鎧。装備者の\n守りの力を高めることができる。", 14005, 0, 1800, "防守のメイル", 4, 1, 1, 10, "物理/魔法防御力＋10％", 14005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で⾒つかった杖。\n癒しの⼒を高めてくれる。", 15001, 0, 1800, "回生杖", 5, 1, 1, 10, "回復強化＋10", 15001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった指輪。\n装備者の生命力を強化する。", 15002, 0, 1800, "豊命輪", 5, 1, 1, 10, "ＨＰ＋10％", 15002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった鎧。\n装備者を物理攻撃から守る。", 15003, 0, 1800, "鉄防甲", 5, 1, 1, 10, "15秒ごとに物理無効バリア展開（【守備】数×500無効）", 15003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかったローブ。\n装備者を魔法攻撃から守る。", 15004, 0, 1800, "魔封衣", 5, 1, 1, 10, "15秒ごとに魔法無効バリア展開（【守備】数×500無効）", 15004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内で見つかった腕輪。\n装備者に再生の力を与える。", 15005, 0, 1800, "再生ノ腕輪", 5, 1, 1, 10, "継続ＨＰ回復（毎秒【守備】数×500回復）", 15005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発見された耳飾りの形\nをした遺物。流水の激しさのよう\nに、活力加速を増幅させる。", 21001, 0, 2800, "流烈の耳飾り", 1, 2, 2, 10, "ＴＰ上昇＋10", 21001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発見された円盾の形を\nした遺物。装備者に星の癒しを与\nえ攻撃をエネルギーに変換する。", 21002, 0, 2800, "星涙の輝盾", 1, 2, 2, 10, "ダメージを受けるたびＴＰ100回復（最大２回）", 21002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発⾒された腕輪の遺物\nあしらわれた蒼珠が、敵を感知し\n力を授ける。", 21003, 0, 2800, "蒼珠の腕輪", 1, 2, 2, 10, "バトル開始時ＴＰ200回復", 21003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発⾒された杖の遺物。\n封じられた星々の神秘が、力の消\n耗を肩代わりしてくれる。", 21004, 0, 2800, "星明りの儀杖", 1, 2, 2, 10, "ＴＰ消費軽減＋4", 21004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発見された、翼の生え\nた靴形の遺物。装備した者に疾風\nの力を施し、行動を速める。", 21005, 0, 2800, "疾風の翼靴", 1, 2, 2, 10, "重複可能の行動速度＋20％", 21005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発⾒された、⾸飾りの\n遺物。宝⽯の輝きで敵を虜にし、\n怪異をもたらすという。", 22001, 0, 2800, "闇至宝アノマリーラ", 2, 2, 2, 10, "状態異常命中＋40", 22001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発見された、杖の形を\nした遺物。杖先のコアから流れる\n邪気が敵に呪いを付与する。", 22002, 0, 2800, "邪眼杖ドゥーム", 2, 2, 2, 10, "敵全体に呪い付与（毎秒【弱体】数×1000ダメージ）", 22002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発見された、短剣の形\nをした遺物。刃に仕込まれた毒が\n気化し、接敵と共に毒を与える。", 22003, 0, 2800, "影刃剣プラール", 2, 2, 2, 10, "敵全体に毒付与（毎秒【弱体】数×1000ダメージ）", 22003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発見された、帽子の形\nをした遺物。絡みつく茨の様に、\n敵の攻撃力を阻害する。", 22004, 0, 2800, "薔薇飾帽イレース", 2, 2, 2, 10, "敵の物理/魔法攻撃力－20％", 22004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発⾒された、⼑の遺物\n血で⾚く染まった⼑⾝で、敵の装\n甲をたやすく断ち割る。", 22005, 0, 2800, "斬赤刃ディバイド", 2, 2, 2, 10, "敵の物理/魔法防御力－20％", 22005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発見された、槍の遺物\n特殊な形の穂先が、敵により深い\n傷を刻み込む。", 23001, 0, 2800, "フェイタリティ", 3, 2, 2, 10, "敵の物理/魔法被クリダメ＋20％", 23001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発見された、刀の形を\nした遺物。秋の紅を映す美しき刃\nは致命の攻撃をさらに強化する。", 23002, 0, 2800, "クレナイノタチ", 3, 2, 2, 10, "物理/魔法クリダメ＋20％", 23002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発⾒された籠⼿の遺\n物。装備者は研ぎ澄まされた強\n力な一撃を放つことができる。", 23003, 0, 2800, "ラプチャーガントレット", 3, 2, 2, 10, "通常攻撃強化＋60", 23003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発⾒された、⼸の遺物\n装備者は烈⾵の⼒を授かり、獲物\nの急所を貫きやすくなる。", 23004, 0, 2800, "スカイストライク", 3, 2, 2, 10, "物理/魔法クリティカル＋20％", 23004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発⾒された斧の遺物。\n繰り出される⼀撃は、掠めるだけ\nで獲物の魂を吸い取る。", 23005, 0, 2800, "インヘイルアックス", 3, 2, 2, 10, "ＨＰ吸収＋20", 23005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発見された、耳飾りの\n形をした遺物。魔石に込められた\n魔力が強化の力を増幅させる。", 24001, 0, 2800, "進化のイヤリング", 4, 2, 2, 10, "バフ強化＋60", 24001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発⾒された、鎧の遺物\n紅き鋼の加護は、守備力を攻撃力\nへと変換する力を持つ。", 24002, 0, 2800, "紅反鋼のアーマー", 4, 2, 2, 10, "物理/魔法攻撃力アップ\n（先頭キャラの物理防御力×10）", 24002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発⾒された、ドレスの\n遺物。精霊の加護が、防魔結界か\nら力を集めてくれる。", 24003, 0, 2800, "聖減術のテラドレス", 4, 2, 2, 10, "物理/魔法攻撃力アップ\n（先頭キャラの魔法防御力×10）", 24003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発見された、大剣の形\nをした遺物。湧き出る炎の力が、\n攻撃の能力を大きく高める。", 24004, 0, 2800, "炎王のグレートソード", 4, 2, 2, 10, "物理/魔法攻撃力＋40％", 24004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発⾒された鎧の遺物。\n千年咲く桜の如く、盤石な堅牢さ\nを装備者に与える。", 24005, 0, 2800, "桜堅牢のコート", 4, 2, 2, 10, "物理/魔法防御力＋20％", 24005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発⾒された杖の遺物。\n装備者に⼤樹の恵みを施し、治癒\n術の才覚を授けてくれる。", 25001, 0, 2800, "創世緑杖", 5, 2, 2, 10, "回復強化＋20", 25001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発見された、指輪の形\nをした遺物。装備者を天空の護り\nで包み込み生命力を増幅させる。", 25002, 0, 2800, "空命護珠", 5, 2, 2, 10, "ＨＰ＋20％", 25002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発見された、鎧の形を\nした遺物。高度な技術で精錬され\nた鋼は、物理攻撃から身を護る。", 25003, 0, 2800, "鋼装堅鎧", 5, 2, 2, 10, "15秒ごとに物理無効バリア展開（【守備】数×1000無効）", 25003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発⾒された、ローブの\n遺物。神樹の蔦が織り込まれ、装\n備者を魔法から護る。", 25004, 0, 2800, "魔護霊装", 5, 2, 2, 10, "15秒ごとに魔法無効バリア展開（【守備】数×1000無効）", 25004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮内部で発⾒された、腕輪の遺\n物。溢れ出す⾃然の⼒は装備者に\n生命の息吹をもたらす。", 25005, 0, 2800, "緑護ノ盾輪", 5, 2, 2, 10, "継続ＨＰ回復（毎秒【守備】数×1000回復）", 25005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮中枢部に隠された黎明の秘宝\nデータ保管のため属性の⼒の断⽚\nが封じられており、内なるアスト\nラルを著しく上昇させる。", 30001, 0, 3800, "エレメントサージオーブ", 0, 0, 3, 10, "属性ボーナス＋100％", 30001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠っていた月を象\nる耳飾り。内部から発する魔力は\n装備者に蝶のような瞬麗さを授け\n活力加速を大きく上昇させる。", 31001, 0, 3800, "瞬閃蝶の月飾り", 1, 3, 3, 10, "ＴＰ上昇＋15", 31001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る宝石を飾った\n円盾。海のような青き魔力は装備\n者に庇護を与え、迫り来る脅威す\nらエネルギーへと昇華させる。", 31002, 0, 3800, "海宝華の煌盾", 1, 3, 3, 10, "ダメージを受けるたびＴＰ100回復（最大３回）", 31002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る聖なる腕輪。\n失われた技術で装飾された宝石が\n装備者に加護を齎し、危機が迫る\nと膨大な力を分け与える。", 31003, 0, 3800, "碧貴石の聖輪", 1, 3, 3, 10, "バトル開始時ＴＰ300回復", 31003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、かつて天界\nに伝えられし杖。天にかざすと鏡\n⽟に篭められた祈りが溢れ出して\n尽きることなき力を授ける。", 31004, 0, 3800, "永天鏡の王笏", 1, 3, 3, 10, "ＴＰ消費軽減＋6", 31004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、天使の加護\nを宿した戦靴。装備するだけで神\n性を授かり、天使のような自在さ\nで空を翔ることができる。", 31005, 0, 3800, "熾天使の翔靴", 1, 3, 3, 10, "重複可能の行動速度＋30％", 31005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮最奥部に鎮祀されし神業の遺\n物。風を司る神々の恩寵が宿され\nており、装備者は無尽蔵の活力が\n疾風の如き速さで体を駆け巡る。", 31006, 0, 9999, "風神の護風恩寵", 1, 5, 3, 10, "ＴＰ上昇＋100", 31006);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、幻獣を象る\n首飾り。この宝石の神秘に魅せら\nれた者は、一切の異変や脅威に抗\nうことができなくなってしまう。", 32001, 0, 3800, "幻獣飾テンタシオン", 2, 3, 3, 10, "状態異常命中＋60", 32001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、月を蝕む杖\n存在するだけで、絶えず呪力の奔\n流を溢れさせ、近づく全ての敵を\n呪いで浸食していく。", 32002, 1, 3800, "深淵蝕杖マリディクト", 2, 3, 3, 10, "敵全体に呪い付与（毎秒【弱体】数×1500ダメージ）", 32002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、黒刃の刺剣\n刃に埋め込まれた宝玉が、絶え間\nなく邪毒を撒き散らし、破滅へと\n刻々と時を数える。", 32003, 0, 3800, "滅刻凶刃ヴェノマス", 2, 3, 3, 10, "敵全体に毒付与（毎秒【弱体】数×1500ダメージ）", 32003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、宝飾をあし\nらったベール。蔽布の下から滲み\n出るオーラが、相手の敵意を解き\nほぐし、無力化させてしまう。", 32004, 0, 3800, "燦然御纏アノラ・ベイラ", 2, 3, 3, 10, "敵の物理/魔法攻撃力－30％", 32004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、⼑⾝に鎖を\n這わせた妖⼑。主の意思に逆らい\n暴れる鎖が怨敵の守りを打ち崩し\n紫黒の凶刃が悉くを断ち斬る。", 32005, 0, 3800, "断壁鎖刃フラグメント", 2, 3, 3, 10, "敵の物理/魔法防御力－30％", 32005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮深層部に静眠せし虚影の装衣\n深淵から出でし蝕影は、存在全て\nを霜雪の如く凍てつかせ、抗う敵\nの剣盾両翼を虚壊させる。", 32006, 0, 9999, "霜影虚装アビスモナーク", 2, 5, 3, 10, "敵の物理/魔法与ダメ－25％\n敵の物理/魔法被ダメ＋25％", 32006);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、地神の力を\n宿した烈槍。大地の力を糧に放つ\n無比の一閃は、地に立つすべての\n敵に甚大なダメージを与える。", 33001, 0, 3800, "リーサルハルバード", 3, 3, 3, 10, "敵の物理/魔法被クリダメ＋30％", 33001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、伝説に語ら\nれる極みの一振り。鳳凰の力を宿\nした真紅の刃は、焔の如き赫く激\n烈な一撃を与える。", 33002, 0, 3800, "オオトリノカタナ", 3, 3, 3, 10, "物理/魔法クリダメ＋30％", 33002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、地核のエネ\nルギーを封じた籠手。振るう一撃\nは、世界を破壊するかの如く、通\n常攻撃を大きく強化する。", 33003, 0, 3800, "アースデストラクション", 3, 3, 3, 10, "通常攻撃強化＋90", 33003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、咎⼈を裁き\nし聖⼸。この弓に選ばれし装備者\nは神⾵の加護を得て、対象に慈悲\nを与えず一瞬で急所を射貫く。", 33004, 0, 3800, "ジャッジメントアロー", 3, 3, 3, 10, "物理/魔法クリティカル＋30％", 33004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、金色の⼤戦\n斧。刈り取った獲物の魂を糧に、\nその絢爛なる刃は燦燦と輝きを増\nしてゆく。", 33005, 0, 3800, "ザ・ハーヴェスト", 3, 3, 3, 10, "ＨＰ吸収＋30", 33005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮最深部に残された久遠の遺物\n神代の大戦より聖騎士に脈々と受\nけ継がれ、装備者へ戦いの記憶と\nともに不滅の力を分け与える。", 33006, 0, 9999, "セレスティアルエイジ", 3, 5, 3, 10, "通常攻撃強化＋500\nＨＰ吸収＋50", 33006);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、炎天の魔力\nを封じた耳飾り。潜在能力を究極\nまで呼び覚まし、強化の力を大幅\nに上昇させる。", 34001, 0, 3800, "極醒のアミュレット", 4, 3, 3, 10, "バフ強化＋90", 34001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、⽩⾦の鎧。\n⽩⻯の鱗を繋ぎ合わせた外装が盟\n友の力を集結させる効果を持ち強\n力無比な一撃を可能にする。", 34002, 0, 3800, "断刃拒絶のアルギュロス", 4, 3, 3, 10, "物理/魔法攻撃力アップ\n（先頭キャラの物理防御力×15）", 34002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、栄華の象徴\nとして仕立てられたドレス。深紅\nに咲き乱れる花の加護は、装備者\nの絶魔の⼒を攻撃⼒へ変換する。", 34003, 0, 3800, "緋華栄華のグラナート", 4, 3, 3, 10, "物理/魔法攻撃力アップ\n（先頭キャラの魔法防御力×15）", 34003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、光⿓の⼒を\n授かりし⼤剣。その⼀振りはかつ\nての栄光の羽ばたきを想起させ、\n極限の覇気を世界に放つ。", 34004, 0, 3800, "覇光帝龍のグローリア", 4, 3, 3, 10, "物理/魔法攻撃力＋60％", 34004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、東の国に伝\nわりし聖鎧。玉の様に透き通る輝\nきを放つ鎧は、装備者に華の加護\nを授け、守護の力を高める。", 34005, 0, 3800, "華舞玲瓏のハルナデシコ", 4, 3, 3, 10, "物理/魔法防御力＋30％", 34005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮深淵部に佇む歴戦無敗の⼤剣\n台座から剣を⼿にした者は天その\nものを冠すかの如き全能感を得て\n千軍を容易く退ける剛⼒を得る。", 34006, 0, 9999, "天戴冠のゼニスブレード", 4, 5, 3, 10, "バトル開始時、物理/魔法攻撃力アップフィールド展開\n（現在値＋50％）", 34006);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、妖精の輝き\nを封じた杖。宝⽟から無限の⽣命\n⼒が溢れ出し、増幅された快癒の\n⼒であらゆる苦しみを取り除く。", 35001, 0, 3800, "妖精霊杖・癒光", 5, 3, 3, 10, "回復強化＋30", 35001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、翠緑に彩ら\nれた指輪。装備者に、かつて豊穣\nに溢れた楽園の光景を想起させ、\n際限なき⽣命⼒を与える。", 35002, 0, 3800, "泉湧命環・豊穣", 5, 3, 3, 10, "ＨＰ＋30％", 35002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、白金の輝き\nを放つ鎧。顕現する翅は、意思を\n持つかのよう、装備者に呼応して\n物理攻撃を断つ障壁を展開する。", 35003, 0, 3800, "白光輝鎧・断壁", 5, 3, 3, 10, "15秒ごとに物理無効バリア展開（【守備】数×1500無効）", 35003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、幽庵の煌き\nを宿す鎧。顕現する翅は、意思を\n持つかのよう、装備者に呼応して\n魔法攻撃を絶つ障壁を展開する。", 35004, 0, 3800, "幽玄煌装・絶魔", 5, 3, 3, 10, "15秒ごとに魔法無効バリア展開（【守備】数×1500無効）", 35004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮の奥深くに眠る、翠宝玉をあ\nしらった腕輪。常に滾々とマナが\n湧き出し、生命力を湛え続ける。", 35005, 0, 3800, "輪廻ノ翡翠珠輪", 5, 3, 3, 10, "継続ＨＰ回復（毎秒【守備】数×1500回復）", 35005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("迷宮最下層に供奉された伝承の環\n選ばれし者がひとたび⼿にすれば\n創造神話の如く、千万無量の⽣命\n⼒を齎すと云われる。", 35006, 0, 9999, "天命授環・伊邪那", 5, 5, 3, 10, "ＨＰ＋100％", 35006);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【美⾷殿】と共に迷宮を冒険する\nための遺物。王家の装備を精巧に\n模しており、味方の⾝体能⼒を⼤\nきく向上させてくれる。", 40001, 0, 3200, "プリンセスフォース", 5, 1, 3, 10, "ＨＰ＋15％\n物理/魔法与ダメ＋15％", 40001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【トゥインクルウィッシュ】と共\nに迷宮を冒険するための遺物。\n３人のアストラルに呼応して、属\n性の力を増幅させてくれる。", 40002, 0, 3200, "アストラルブースト", 4, 1, 3, 10, "属性ボーナス＋50％", 40002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【サレンディア救護院】と共に迷\n宮を冒険するための遺物。主人が\n築いた信頼関係のおかげで、商品\nの価格を値引きしてもらえる。", 40003, 0, 3200, "サレンディアエンゲージ", 1, 1, 3, 10, "ショップの販売価格－10％", 40003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【王宮騎士団】と共に迷宮を冒険\nするための遺物。団長の愛⽤品を\n模し会⼼率と引き換えに、会⼼時\nの威⼒を⾼めてくれる。", 40004, 0, 3200, "ナイツオブフェイス", 3, 1, 3, 10, "物理/魔法クリダメ＋50％\n物理/魔法クリティカル－25％", 40004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【ラビリンス】と共に迷宮を冒険\nするための遺物。迷宮女王はその\n権能でナイトがどこに居ようとも\n即座に参戦してくれる。", 40005, 0, 3200, "ラビリンスオーソリティ", 2, 1, 3, 10, "挑戦開始時にラビリスタが加入", 40005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【カルミナ】と共に迷宮を冒険す\nるための遺物。これを振るう者の\n熱き声援は、ステージに立つ者の\n能力をより一層高めてくれる。", 40006, 0, 3200, "イルミネイトカルミナ", 4, 1, 3, 10, "物理/魔法攻撃力＋15％\nバフ強化＋15", 40006);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【悪魔偽王国軍】と共に迷宮を冒\n険するための遺物。紅き両刃から\n禍々しく迸る魔力の前では、いか\nなる敵だろうと戦意を失う。", 40007, 0, 3200, "ブルートナハト", 1, 1, 3, 10, "敵のＴＰ上昇－15", 40007);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【牧場】と共に迷宮を冒険するた\nめの遺物。被ったらたちまちその\n場で最も目立つ存在となり、すべ\nての攻撃を引きつけてしまう。", 40008, 0, 3200, "エリザベスガーディアン", 5, 1, 3, 10, "バトル開始時に最もＨＰが多いキャラが敵を挑発", 40008);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【メルクリウス財団】と共に迷宮\nを冒険するための遺物。人から決\nして多く受け取らず、生まれ持っ\nた財のみで戦いぬく高潔さの証。", 40009, 0, 3200, "ノブレスウィスタリア", 3, 1, 3, 10, "初期アルファルピ+3000\nアルファルピ獲得量－10%", 40009);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【トワイライトキャラバン】と共\nに迷宮を冒険するための遺物。二\n本の刀が見せる煌めきは、悪党ど\nもの気炎を容易く挫く。", 40010, 0, 3200, "兵法二海一流", 2, 1, 3, 10, "デバフ強化＋20", 40010);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【リトルリリカル】と共に迷宮を\n冒険するための遺物。中に宿って\nいる強い絆が、どこにいても３人\nをふたたび繋いでくれる。", 40011, 0, 3200, "絆のリボン", 3, 1, 3, 10, "挑戦開始時にミソギ＆ミミ＆キョウカが加入", 40011);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【自警団】と共に迷宮を冒険する\nための遺物。護りの奥義が記され\nており、読み込めば攻撃から身を\n守る技術を得ることができる。", 40012, 0, 3200, "琉球犬甲唄", 4, 1, 3, 10, "バトル開始時に先頭キャラに物理/魔法防御力+50%", 40012);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【フォレスティエ】と共に迷宮を\n冒険するための遺物。森の息吹を\n内に秘め、所持しているだけで味\n方に調和の力を授ける。", 40013, 0, 3200, "フォレストハーモニー", 5, 1, 3, 10, "バトル開始時に調和状態", 40013);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【ルーセント学院】と共に迷宮を\n冒険するための遺物。誘惑した相\n手の生気を少しずつ削ぎ、気付か\nぬ間に甘い終焉を迎えさせる。", 40014, 0, 3200, "チャームファタール", 2, 1, 3, 10, "1秒ごとに誘惑状態の敵に最大ＨＰの5％の魔法割合ダメージ（最大50万ダメージ）", 40014);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【美⾷殿】と共に迷宮を冒険する\nための遺物。冒険の道中で絆を結\nべば結ぶほどに、味⽅の攻撃⼒を\n⾼めてくれる。", 50001, 0, 3200, "プリンセスエンチャント", 4, 1, 3, 10, "物理/魔法攻撃力アップ（加入キャラ数×4％、最大100％）", 50001);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【トゥインクルウィッシュ】と共\nに迷宮を冒険するための遺物。ギ\nルドマスターの諦めない心が、味\n方を一度だけ敗北から守る。", 50002, 1, 3200, "トゥインクルブレス", 5, 1, 3, 10, "ボスバトルを除いて一度だけバトル敗北を免除", 50002);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【サレンディア救護院】と共に迷\n宮を冒険するための遺物。主人の\n気品を漂わせる剣は、築いた富を\n⼒に変転させる効果を持つ。", 50003, 0, 3200, "サレンディアノーブル", 3, 1, 3, 10, "通常攻撃強化アップ（アルファルピ所持数×0.01、最大100）", 50003);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【王宮騎士団】と共に迷宮を冒険\nするための遺物。副団長の催す闘\n争の宴は、敵味⽅が受けるダメー\nジをみな悉く増加させる。", 50004, 0, 3200, "レジーナガーラ", 2, 1, 3, 10, "敵の物理/魔法被ダメ＋25％\n味方の物理/魔法被ダメ＋25％", 50004);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【ラビリンス】と共に迷宮を冒険\nするための遺物。マスターの⼒を\n冠した剣は、開発者権限の⼀部を\n解放し、遺物を即座に獲得する。", 50005, 0, 3200, "マスターオブラビリンス", 1, 1, 3, 10, "挑戦開始時にランダムな★1の迷宮遺物を１個獲得", 50005);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【カルミナ】と共に迷宮を冒険す\nるための遺物。ハンドマイクを通\nじて拡がっていく歌声は、味方の\n疲労をふき飛ばす。", 50006, 0, 3200, "ヴォイスフォーユー", 4, 1, 3, 10, "30秒ごとに物理/魔法攻撃力ダウン解除", 50006);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【悪魔偽王国軍】と共に迷宮を冒\n険するための遺物。重く振りかざ\nす一撃は、斬り裂いた獲物の生気\nを我が物とする。", 50007, 0, 3200, "ディアボロスフィアー", 1, 1, 3, 10, "15秒ごとにＴＰ固定量100回復\n敵のＴＰ100ダウン", 50007);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【牧場】と共に迷宮を冒険するた\nめの遺物。持ち主のやる気を呼び\n起こし、ぐうたらさを１回だけ無\n効化できる。あくまで１回だけ。", 50008, 0, 3200, "ドングリースピリット", 5, 1, 3, 10, "行動不能無効１回", 50008);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【メルクリウス財団】と共に迷宮\nを冒険するための遺物。富を積め\nば積むほど精神を集中させ、必殺\nの一突きを敵に見舞う。", 50009, 0, 3200, "リヴァイアサンコール", 3, 1, 3, 10, "物理/魔法クリダメアップ（アルファルピ所持数×0.01%、最大100%）", 50009);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【トワイライトキャラバン】と共\nに迷宮を冒険するための遺物。さ\nまざまな者たちの個性を学習し、\n敵を苦しめる術に転化する。", 50010, 0, 3200, "バインディングローズ", 2, 1, 3, 10, "敵への継続ダメージアップ（加入キャラ数×10％、最大50万ダメージ）", 50010);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【リトルリリカル】と共に迷宮を\n冒険するための遺物。履くと元気\nが溢れ出し、走り回ってより多く\nの仲間を勧誘できる。", 50011, 1, 3200, "トリックランナー", 0, 0, 3, 10, "コネクトサインマスの抽選回数+1（1回）", 50011);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【自警団】と共に迷宮を冒険する\nための遺物。姫さま親衛隊の精鋭\n隊員たちで、仲間をより増やすた\nめに日夜勤しんでいる。", 50012, 3, 3200, "姫さま親衛隊勧誘係", 0, 0, 3, 10, "バトル勝利後時の仲間キャラ加入数+1（3回）", 50012);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【フォレスティエ】と共に迷宮を\n冒険するための遺物。きらりと輝\nく流れ星が、多くのアイテムを手\nに入れる幸運を呼び寄せる。", 50013, 1, 3200, "フォーチュンミーティア", 0, 0, 3, 10, "迷宮遺物マスの抽選回数+1（1回）", 50013);
INSERT INTO `v1_e77aee01f6ebf0a04f82dbce539d85688f36d3f026f680bade29730da16d9025` VALUES ("【ルーセント学院】と共に迷宮を\n冒険するための遺物。悪魔的なほ\nどに真紅の艶めきは、見た者の目\nを釘付けにし、二度と逃さない。", 50014, 1, 3200, "ベルベットルージュ", 0, 0, 3, 10, "敵の誘惑時間+50％", 50014);
